import{_ as i,o as t,c as a,a4 as o}from"./chunks/framework.CtnSHCpE.js";const u=JSON.parse('{"title":"GPG ON z/OS","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/GpgOnZOS.md","filePath":"Guides/GpgOnZOS.md","lastUpdated":1726858945000}'),n={name:"Guides/GpgOnZOS.md"};function r(s,e,p,d,l,c){return t(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="gpg-on-z-os" tabindex="-1"><strong>GPG ON z/OS</strong> <a class="header-anchor" href="#gpg-on-z-os" aria-label="Permalink to &quot;**GPG ON z/OS**&quot;">​</a></h1><h3 id="what-is-gpg" tabindex="-1">What is GPG? <a class="header-anchor" href="#what-is-gpg" aria-label="Permalink to &quot;What is GPG?&quot;">​</a></h3><p>GPG stands for &quot;GNU Privacy Guard,&quot; which is a free and open-source software application used for encrypting and decrypting data. It is based on the OpenPGP (Pretty Good Privacy) standard, which provides cryptographic privacy and authentication for data communication.</p><p>GPG uses a combination of symmetric-key and public-key cryptography to secure data. Symmetric-key cryptography involves using the same key for both encryption and decryption, while public-key cryptography uses a pair of keys: a public key for encryption and a private key for decryption.</p><p>GPG allows users to generate key pairs consisting of a public key and a private key. The public key can be freely distributed, while the private key must be kept secret. With GPG, users can encrypt data using the recipient&#39;s public key, ensuring that only the intended recipient can decrypt and access the information using their private key.</p><p>GPG also supports digital signatures, which provide a way to verify the authenticity and integrity of data. By signing a document with their private key, a user can demonstrate that the document has not been tampered with and was indeed created by them. The signature can be verified using the corresponding public key.</p><p>Overall, GPG is commonly used for secure communication, email encryption, file encryption, and verifying the authenticity of software distributions. It is widely regarded as a reliable and trusted tool for ensuring privacy and security in digital communications.</p><h3 id="how-do-i-generate-a-gpg-key" tabindex="-1">How do I generate a GPG key? <a class="header-anchor" href="#how-do-i-generate-a-gpg-key" aria-label="Permalink to &quot;How do I generate a GPG key?&quot;">​</a></h3><p>In the terminal, enter the following command to generate a new GPG key pair:</p><pre><code>gpg --generate-key
</code></pre><p>This command initiates the key generation process.</p><p>You will be prompted enter your name and email address: Provide your full name and the email address associated with the key. This information will be included in the key&#39;s metadata.</p><p>Set a passphrase: You will be prompted to set a passphrase for your key. This passphrase will protect your private key and should be strong and memorable. Type in a passphrase and press Enter. Make sure to choose a secure passphrase and keep it confidential.</p><p>Once the key generation process is complete, GPG will display information about your new key pair, including the key ID and fingerprint. The key ID is used to identify your key, and the fingerprint is a unique identifier for your key pair. You can use this information to share your public key with others.</p><pre><code>pub   rsa3072 2021-02-09 [SC] [expires: 2022-02-09]
      3782CBB60147010B330523DD26FBCC7836BF353A
uid                      John Doe (ZOS Open tools) &lt;johndoe@example.com&gt;
sub   rsa3072 2021-02-09 [E] [expires: 2022-02-09]
</code></pre><h3 id="how-do-i-view-key-fingerprint" tabindex="-1">How do I view key fingerprint? <a class="header-anchor" href="#how-do-i-view-key-fingerprint" aria-label="Permalink to &quot;How do I view key fingerprint?&quot;">​</a></h3><p>A key fingerprint is a representation of the key&#39;s characteristics and serves as a reliable way to verify the integrity and authenticity of a key. To display the fingerprint at any time, use this command, substituting your email address</p><pre><code>gpg --fingerprint &lt;email id&gt;
</code></pre><p>Your GPG key ID consists of 8 hex digits identifying the public key. In the example above, the GPG key ID is <code>36BF353A</code>.</p><h3 id="how-do-i-get-your-public-key-and-store-it" tabindex="-1">How do I get your public key and store it? <a class="header-anchor" href="#how-do-i-get-your-public-key-and-store-it" aria-label="Permalink to &quot;How do I get your public key and store it?&quot;">​</a></h3><p>If you want to give or send a file copy of your key to someone, use this command to write it to an ASCII text file:</p><p><code>gpg --export --armor &lt;email id&gt; &gt; &lt;name&gt;-pubkey.asc</code></p><h3 id="how-do-i-sign-git-commits-using-gpg-key" tabindex="-1">How do I Sign Git commits using GPG key? <a class="header-anchor" href="#how-do-i-sign-git-commits-using-gpg-key" aria-label="Permalink to &quot;How do I Sign Git commits using GPG key?&quot;">​</a></h3><ol><li><p>Add your public GPG Key to your account on github.com and refer the <a href="https://docs.github.com/en/authentication/managing-commit-signature-verification/adding-a-gpg-key-to-your-github-account" target="_blank" rel="noreferrer">link</a> for steps.</p></li><li><p>Tell git about your public key which will be used for signing. You can get steps from <a href="https://docs.github.com/en/authentication/managing-commit-signature-verification/telling-git-about-your-signing-key#telling-git-about-your-gpg-key" target="_blank" rel="noreferrer">here</a></p></li><li><p>Now you can sign your commit using command (provide your phrase on prompt)</p><p><code>git commit -S -m &quot;YOUR_COMMIT_MESSAGE&quot;</code></p></li><li><p>When you&#39;ve finished creating commits locally, push them to your remote repository on GitHub:</p><p><code>git push </code></p></li><li><p>On GitHub, navigate to your pull requestO and on the pull request, click Commits. To view more detailed information about the verified signature, click <code>Verified</code>.</p></li></ol><h3 id="how-do-i-sign-files" tabindex="-1">How do I sign files? <a class="header-anchor" href="#how-do-i-sign-files" aria-label="Permalink to &quot;How do I sign files?&quot;">​</a></h3><ol><li><p>Any file can be signed using command below.</p><p><code>gpg --output &lt;file.name&gt;.sig --sign &lt;file-name&gt;</code></p></li><li><p>Signed file can be verified using:</p><p><code>gpg --verify &lt;file.name&gt;.sig</code></p></li><li><p>To verify the signature and extract the file use the --decrypt option. The signed file to verify and recover is input and the recovered document is output.</p><p><code>gpg --output zoslib-zopen.20230511_114620.zos.pax.Z --decrypt zoslib-zopen.20230511_114620.zos.pax.Z.gpg</code></p></li></ol><h3 id="how-do-i-create-detached-signature-and-sign-a-file" tabindex="-1">How do I create detached signature and sign a file? <a class="header-anchor" href="#how-do-i-create-detached-signature-and-sign-a-file" aria-label="Permalink to &quot;How do I create detached signature and sign a file?&quot;">​</a></h3><ol><li><p>A detached signature can be created and a file can signed using the following command:</p><p><code>gpg --output &lt;file.name&gt;.sig --detach-sig &lt;file-name&gt;</code></p></li><li><p>Both file and the detached signature are needed to verify the signature using --verify option:</p><p><code>gpg --verify &lt;file.name&gt;.sig &lt;file.name&gt;</code></p></li></ol><h3 id="example" tabindex="-1">Example: <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example:&quot;">​</a></h3><ol><li><p>Download signed bash tool in tar.gz.sig format using command shown below:</p><p><code>curl -k -O http://ftp.vim.org/ftp/ftp/gnu/bash/bash-5.2.15.tar.gz.sig</code></p></li><li><p>Download the bash tool in tar.gs format using command below:</p><p><code>curl -k -O http://ftp.vim.org/ftp/ftp/gnu/bash/bash-5.2.15.tar.gz</code></p></li><li><p>Download the public GNU keyring using command shown below:</p><p><code>curl -k -O https://ftp.gnu.org/gnu/gnu-keyring.gpg</code></p></li><li><p>Verify the downloaded tar file, using command:</p><p><code>gpg --verify --keyring ./gnu-keyring.gpg bash-5.2.15.tar.gz.sig</code></p></li><li><p>The output of the step 4 is:</p><p><code>gpg: Signature made Tue Dec 13 12:13:54 2022 EST</code><code>gpg: using DSA key 7C0135FB088AAF6C66C650B9BB5869F064EA74AB</code><code>gpg: Good signature from &quot;Chet Ramey &lt;chet@cwru.edu&gt;&quot; [unknown]</code></p></li></ol><h3 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h3><ul><li><a href="https://gnupg.org/index.html" target="_blank" rel="noreferrer">GPG Home Page</a></li><li>To install GPG on z/OS systems <a href="https://github.com/zopencommunity/gpgport/releases" target="_blank" rel="noreferrer">visit</a></li></ul>`,32)])])}const h=i(n,[["render",r]]);export{u as __pageData,h as default};
